frappe.ui.form.on('Employee', {
    refresh(frm) {
        // Make specific fields mandatory dynamically
        const mandatory_fields = [
            'cell_number',
            'ctc',
            'user_id',
            'employee_tin',
            'expense_approver',
            'leave_approver',
            'shift_request_approver'
        ];

        mandatory_fields.forEach(fieldname => {
            frm.set_df_property(fieldname, 'reqd', 1);
        });
    }
});

frappe.ui.form.on('Payment Entry', {
    refresh: function(frm) {
        if (frm.doc.references && frm.doc.references.length > 0) {
            let purchase_invoice_ref = frm.doc.references.find(d => d.reference_doctype === 'Purchase Invoice');
            if (purchase_invoice_ref) {
                frm.set_value('custom_purchase_invoice', purchase_invoice_ref.reference_name);
            }
        }
    },
    references_on_form_rendered: function(frm) {
        // Also handle dynamically when references are changed
        if (frm.doc.references && frm.doc.references.length > 0) {
            let purchase_invoice_ref = frm.doc.references.find(d => d.reference_doctype === 'Purchase Invoice');
            if (purchase_invoice_ref) {
                frm.set_value('custom_purchase_invoice', purchase_invoice_ref.reference_name);
            }
        }
    }
});

