frappe.ui.form.on('Leave Application', {
	refresh(frm) {
    	 toggleHalfDayDateMandatory(frm);
	},
	half_day: function(frm){
	   toggleHalfDayDateMandatory(frm);
	}
});

function toggleHalfDayDateMandatory(frm) {
    if (frm.doc.half_day) {
        frm.toggle_display('half_day_date', false); // Show it, but not mandatory
        // Optionally clear the value if half_day is checked and it's no longer needed
        // frm.set_value('half_day_date', null);
    }
    // Refresh the field to apply the mandatory status change visually
    frm.refresh_field('half_day_date');
}
